library(shiny)
library(shinydashboard)

# =========================
# FUNCIONES GENERALES
# =========================

R_serie_id &lt;- function(n, p) p^n
R_par_id &lt;- function(n, p) 1 - (1 - p)^n

# =========================
# UI
# =========================

ui &lt;- dashboardPage(
    dashboardHeader(title = "Reliability"),

    dashboardSidebar(
        sidebarMenu(
            menuItem("Failure Rate", tabName = "failure"),
            menuItem("Exponential Systems", tabName = "exp"),
            menuItem("Series Systems", tabName = "series"),
            menuItem("Parallel Systems", tabName = "parallel")
        )
    ),

    dashboardBody(
        withMathJax(),

        tabItems(

            # =========================
            # 1. FAILURE RATE (PRIMERA)
            # =========================

            tabItem(tabName = "failure",
                    fluidRow(
                        box(width = 4,
                            sliderInput("t_fail", "Time points", 10, 100, 50),
                            radioButtons("fail_type", "Function:",
                                         c("Reliability" = "R", "Failure rate" = "h")),
                            radioButtons("fail_sys", "System:",
                                         c("Initial" = "init",
                                           "Series" = "serie",
                                           "Parallel" = "paralelo"))
                        ),

                        box(width = 8,
                            plotOutput("fail_plot"),
                            uiOutput("fail_eq")
                        )
                    )
            ),

            # =========================
            # 2. EXPONENCIAL
            # =========================

            tabItem(tabName = "exp",
                    fluidRow(
                        box(width = 4,
                            radioButtons("exp_type", "System:",
                                         c("Series" = "serie", "Parallel" = "paralelo")),
                            sliderInput("L1", "Lambda 1", 0.001, 1, 0.5),
                            sliderInput("L2", "Lambda 2", 0.001, 1, 0.5)
                        ),

                        box(width = 8,
                            plotOutput("exp_plot"),
                            uiOutput("exp_eq"),
                            textOutput("exp_mttf")
                        )
                    )
            ),

            # =========================
            # 3. SERIES
            # =========================

            tabItem(tabName = "series",
                    fluidRow(
                        box(width = 4,
                            sliderInput("n_s", "n", 2, 20, 3),
                            sliderInput("p_s", "p", 0, 1, 0.5)
                        ),

                        box(width = 8,
                            textOutput("series_res"),
                            plotOutput("series_plot")
                        )
                    )
            ),

            # =========================
            # 4. PARALLEL
            # =========================

            tabItem(tabName = "parallel",
                    fluidRow(
                        box(width = 4,
                            sliderInput("n_p", "n", 2, 20, 3),
                            sliderInput("p_p", "p", 0, 1, 0.5)
                        ),

                        box(width = 8,
                            textOutput("par_res"),
                            plotOutput("par_plot")
                        )
                    )
            )
        )
    )
)

# =========================
# SERVER
# =========================

server &lt;- function(input, output) {

    # =========================
    # FAILURE RATE
    # =========================

    output$fail_plot &lt;- renderPlot({
        t &lt;- seq(1,100,length.out=input$t_fail)

        if (input$fail_type=="R") {
            if (input$fail_sys=="init") {
                plot(t,2/(exp(t)+1),type="l",col="red",
                     main="Reliability Function")
            } else if (input$fail_sys=="serie") {
                plot(t,8/(exp(t)+1)^3,type="l",
                     main="Series System")
            } else {
                plot(t,1-((exp(t)-1)^3/(exp(t)+1)^3),type="l",
                     main="Parallel System")
            }
        } else {
            plot(t,exp(t)/(exp(t)+1),type="l",col="blue",
                 main="Failure Rate")
        }
    })

    output$fail_eq &lt;- renderUI({
        if (input$fail_type=="h") {
            withMathJax("$$r(t)=\\frac{e^t}{e^t+1}$$")
        } else if (input$fail_sys=="serie") {
            withMathJax("$$R(t)=\\frac{8}{(e^t+1)^3}$$")
        } else if (input$fail_sys=="paralelo") {
            withMathJax("$$R(t)=1-\\frac{(e^t-1)^3}{(e^t+1)^3}$$")
        } else {
            withMathJax("$$R(t)=\\frac{2}{e^t+1}$$")
        }
    })

    # =========================
    # EXPONENCIAL
    # =========================

    output$exp_plot &lt;- renderPlot({
        t &lt;- seq(0, 50, length.out = 100)

        if (input$exp_type == "serie") {
            R &lt;- exp(-(input$L1 + input$L2)*t)
            plot(t, R, type="l", col="red", main="Series Reliability")
        } else {
            R &lt;- 1 - (1-exp(-input$L1*t))*(1-exp(-input$L2*t))
            plot(t, R, type="l", col="blue", main="Parallel Reliability")
        }
    })

    output$exp_eq &lt;- renderUI({
        if (input$exp_type == "serie") {
            withMathJax("$$R(t)=e^{-(\\lambda_1+\\lambda_2)t}$$")
        } else {
            withMathJax("$$R(t)=1-(1-e^{-\\lambda_1 t})(1-e^{-\\lambda_2 t})$$")
        }
    })

    output$exp_mttf &lt;- renderText({
        if (input$exp_type == "serie") {
            paste("MTTF:", round(1/(input$L1+input$L2),4))
        } else {
            paste("MTTF:", round(input$L1/(input$L2^2+input$L1*input$L2),4))
        }
    })

    # =========================
    # SERIES
    # =========================

    output$series_res &lt;- renderText({
        paste("Reliability:", round(input$p_s^input$n_s,4))
    })

    output$series_plot &lt;- renderPlot({
        n &lt;- 2:50
        plot(n, input$p_s^n, type="l",
             main="R vs n (Series)", ylab="R")
    })

    # =========================
    # PARALLEL
    # =========================

    output$par_res &lt;- renderText({
        paste("Reliability:", round(1-(1-input$p_p)^input$n_p,4))
    })

    output$par_plot &lt;- renderPlot({
        n &lt;- 2:50
        plot(n, 1-(1-input$p_p)^n, type="l",
             main="R vs n (Parallel)", ylab="R")
    })
}

shinyApp(ui, server)
